// Simple keyword-overlap clustering
// For production: use cosine similarity or call OpenAI embeddings
const items = $input.all().map(i => i.json)

// Build clusters by finding items with >= 2 shared keywords
const clusters = []
const assigned = new Set()

for (let i = 0; i < items.length; i++) {
  if (assigned.has(items[i].id)) continue

  const seed = items[i]
  const seedKw = new Set((seed.keywords || []).map(k => k.toLowerCase()))
  if (seedKw.size === 0) continue

  const group = [seed]
  assigned.add(seed.id)

  for (let j = i + 1; j < items.length; j++) {
    if (assigned.has(items[j].id)) continue
    const otherKw = (items[j].keywords || []).map(k => k.toLowerCase())
    const shared  = otherKw.filter(k => seedKw.has(k))
    if (shared.length >= 2) {
      group.push(items[j])
      assigned.add(items[j].id)
    }
  }

  if (group.length >= 2) {
    // Aggregate keywords
    const allKw = group.flatMap(it => it.keywords || [])
    const kwFreq = {}
    allKw.forEach(k => { kwFreq[k] = (kwFreq[k] || 0) + 1 })
    const topKw = Object.entries(kwFreq).sort((a,b) => b[1]-a[1]).slice(0,10).map(([k]) => k)

    clusters.push({
      title:           topKw.slice(0,3).join(' + '),
      keywords:        topKw,
      entities:        {},
      source_item_ids: group.map(it => it.id),
      item_count:      group.length,
      velocity:        group.length,  // items in last 2h = velocity proxy
      org_id:          seed.org_id
    })
  }
}

return clusters.map(c => ({ json: c }))
